module Counter (
	input obf_clk,
	input reset,
	output reg [3:0] count
);

always @(posedge obf_clk) begin
    if (reset) begin
        count <= 4'd0;
    end else begin
        count <= count + 1;
        if (count == 4'd15) begin
            count <= 4'd0;
        end
    end
end

endmodule
